// ❌ BAD - Task always allocates even when cache hit is synchronous
public async Task<ProductDto> GetProductAsync(int id)
{
    if (_cache.TryGetValue(id, out var cached)) return cached;
    return await _db.Products.FindAsync(id);
}

// ✅ GOOD - ValueTask avoids allocation on the cache-hit path
public ValueTask<ProductDto> GetProductAsync(int id)
{
    if (_cache.TryGetValue(id, out var cached))
        return new ValueTask<ProductDto>(cached); // zero allocation
    return new ValueTask<ProductDto>(LoadFromDbAsync(id));
}

// ❌ BAD - without volatile the JIT may cache _running in a register; loop never exits
private bool _running = true;
public void Worker() { while (_running) { Process(); } }

// ✅ GOOD - volatile forces re-read from memory each iteration
private volatile bool _running = true;
public void Stop()   => _running = false;
public void Worker() { while (_running) { Process(); } }

// ❌ BAD - cannot await inside lock; continuation may resume on wrong thread
async Task ProcessOrderAsync(Order order)
{
    lock (_sync) { await _db.SaveAsync(order); } // compiler error / runtime risk
}

// ✅ GOOD - SemaphoreSlim is awaitable; safe async mutual exclusion
private readonly SemaphoreSlim _gate = new SemaphoreSlim(1, 1);
async Task ProcessOrderAsync(Order order)
{
    await _gate.WaitAsync();
    try { await _db.SaveAsync(order); }
    finally { _gate.Release(); }
}

// ❌ BAD - hand-rolled lock + Queue; not thread-safe without careful locking
private Queue<Order> _queue = new Queue<Order>();
void Enqueue(Order o) { lock(_queue) _queue.Enqueue(o); }

// ✅ GOOD - Channel handles thread safety, backpressure, and async natively
var channel = Channel.CreateBounded<Order>(capacity: 100);
// Producer
_ = Task.Run(async () => {
    foreach (var order in incomingOrders)
        await channel.Writer.WriteAsync(order);
    channel.Writer.Complete();
});
// Consumer
await foreach (var order in channel.Reader.ReadAllAsync())
    await FulfillOrderAsync(order);

