// ❌ BAD - timeout fires but API call keeps running, leaking the connection
var work = _fraudApi.CheckAsync(transactionId);
if (await Task.WhenAny(work, Task.Delay(2000)) != work)
    throw new TimeoutException();
return await work;

// ✅ GOOD - CTS cancels the real call on timeout; loser is observed
using var cts = new CancellationTokenSource();
var work  = _fraudApi.CheckAsync(transactionId, cts.Token);
var delay = Task.Delay(2000, cts.Token);
if (await Task.WhenAny(work, delay) == delay)
{
    cts.Cancel();
    throw new TimeoutException("Fraud check timed out");
}
cts.Cancel(); // cancel the delay
return await work;

