public async Task<List<SalesRecord>> ExportSalesAsync(int year)
    => await _db.SalesRecords.Where(r => r.Year == year).ToListAsync();

// ✅ GOOD - streams rows; memory stays flat regardless of row count
public async IAsyncEnumerable<SalesRecord> StreamSalesAsync(
    int year, [EnumeratorCancellation] CancellationToken ct = default)
{
    await foreach (var r in _db.SalesRecords
        .Where(r => r.Year == year)
        .AsAsyncEnumerable().WithCancellation(ct))
        yield return r;
}
// Consumer
