// ❌ BAD - sequential: total time = sum of all 500 calls
foreach (var id in orderIds)
    results.Add(await _orderApi.GetAsync(id));

// ❌ BAD - unbounded concurrency: can DDoS the API or exhaust connections
var tasks = orderIds.Select(id => _orderApi.GetAsync(id));
var all = await Task.WhenAll(tasks);

// ✅ GOOD - throttled: 10 concurrent calls, gentle on the API
await Parallel.ForEachAsync(orderIds,
    new ParallelOptions { MaxDegreeOfParallelism = 10 },
    async (id, ct) => results.Add(await _orderApi.GetAsync(id, ct)));

